73	// validateTrustNamespace validates that the trust namespace exists.
74	func (r *Reconciler) validateTrustNamespace(namespace string) error {
75		exists, err := r.namespaceExists(namespace)
76		if err != nil {
77			return fmt.Errorf("failed to check if namespace %q exists: %w", namespace, err)
78		}
79		if !exists {
80			return fmt.Errorf("trust namespace %q does not exist, create the namespace before creating TrustManager CR", namespace)
81		}
82		return nil
83	}
